@app.route('/api/<path:service_path>', methods=['GET', 'POST', 'PUT', 'DELETE'])
def api_gateway(service_path):
    # Validate upstream endpoint
    upstream_endpoint = f"https://api.example.com/{service_path}"
    if not validate_upstream_endpoint(upstream_endpoint):
        return jsonify({'error': 'Unauthorized endpoint'}), 403
    
    # Extract and validate token
    claims = extract_claims()
    if not claims:
        return jsonify({'error': 'Invalid or missing token'}), 401
    
    # Sanitize request data
    data = sanitize_input(request.get_json() or {})
    
    # Forward to backend
    headers = {
        'Authorization': request.headers.get('Authorization', ''),
        'user_claims': claims
    }
    
    try:
        response = forward_to_backend(
            endpoint=upstream_endpoint,
            method=request.method,
            headers=headers,
            data=data
        )
        
        return jsonify(response.json()), response.status_code
    except Exception as e:
        return jsonify({'error': 'Backend service error'}), 500

